@Service
public class BillingService {

    public void processBatch(List<Long> ids) {
        for (Long id : ids) {
            // BUG: this.charge(...) calls the RAW object, bypassing the proxy.
            // No new transaction is started; @Transactional is IGNORED.
            this.charge(id);
        }
    }

    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void charge(Long id) {
        // intended to commit/rollback per id, but never does when self-invoked
    }
}

@Service
public class BillingService {
    private final ChargeService chargeService; // separate bean -> real proxy
    public BillingService(ChargeService chargeService) {
        this.chargeService = chargeService;
    }
    public void processBatch(List<Long> ids) {
        for (Long id : ids) {
            try {
                chargeService.charge(id); // goes through the proxy -> REQUIRES_NEW honored
            } catch (ChargeException e) {
                log.warn("Skipping {} ", id, e); // isolated rollback per id
            }
        }
    }
}

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.disable())                 // stateless API
            .sessionManagement(s -> s.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/actuator/health", "/api/public/**").permitAll()
                .requestMatchers(HttpMethod.POST, "/api/orders").hasAuthority("SCOPE_orders:write")
                .anyRequest().authenticated())
            .oauth2ResourceServer(o -> o.jwt(Customizer.withDefaults()));
        return http.build();
    }
}

