@Service
public class TransferService {
    private final AccountRepository accounts;
    public TransferService(AccountRepository accounts) { this.accounts = accounts; }

    @Transactional // default: does NOT roll back on checked exceptions
    public void transfer(long from, long to, BigDecimal amt) throws InsufficientFundsException {
        debit(from, amt);   // may throw checked -> debit still commits!
        credit(to, amt);
        this.audit(from, to, amt); // self-invocation -> REQUIRES_NEW ignored
    }
    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void audit(long from, long to, BigDecimal amt) { /* insert audit row */ }
}

// FIXED
@Service
public class TransferService {
    private final AccountRepository accounts;
    private final AuditService auditService; // separate bean -> real proxy
    public TransferService(AccountRepository accounts, AuditService auditService) {
        this.accounts = accounts;
        this.auditService = auditService;
    }

    // rollbackFor makes the checked exception roll back the transfer
    @Transactional(rollbackFor = InsufficientFundsException.class)
    public void transfer(long from, long to, BigDecimal amt) throws InsufficientFundsException {
        // audit in its OWN committed transaction first, so it survives a rollback
        auditService.audit(from, to, amt);
        Account src = accounts.findByIdForUpdate(from);
        if (src.getBalance().compareTo(amt) < 0) {
            throw new InsufficientFundsException(from); // now rolls back debit/credit
        }
        src.debit(amt);
        accounts.findByIdForUpdate(to).credit(amt);
    }
}

@Service
public class AuditService {
    private final AuditRepository audits;
    public AuditService(AuditRepository audits) { this.audits = audits; }

    @Transactional(propagation = Propagation.REQUIRES_NEW)
    public void audit(long from, long to, BigDecimal amt) {
        audits.save(new AuditRow(from, to, amt, Instant.now()));
    }
}

public class ResourceNotFoundException extends RuntimeException {
    public ResourceNotFoundException(String msg) { super(msg); }
}

@RestControllerAdvice
public class GlobalExceptionHandler {
    private static final Logger log = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ProblemDetail onValidation(MethodArgumentNotValidException ex) {
        var pd = ProblemDetail.forStatus(HttpStatus.BAD_REQUEST);
        pd.setTitle("Validation failed");
        pd.setDetail("One or more fields are invalid");
        var errors = ex.getBindingResult().getFieldErrors().stream()
            .collect(Collectors.toMap(FieldError::getField,
                    fe -> Optional.ofNullable(fe.getDefaultMessage()).orElse("invalid"),
                    (a, b) -> a));
        pd.setProperty("errors", errors);
        return pd;
    }

    @ExceptionHandler(ResourceNotFoundException.class)
    public ProblemDetail onNotFound(ResourceNotFoundException ex) {
        var pd = ProblemDetail.forStatusAndDetail(HttpStatus.NOT_FOUND, ex.getMessage());
        pd.setTitle("Resource not found");
        return pd;
    }

    @ExceptionHandler(Exception.class)
    public ProblemDetail onUnexpected(Exception ex) {
        String correlationId = UUID.randomUUID().toString();
        // Full diagnostics stay on the server, keyed by correlation id
        log.error("Unhandled exception correlationId={}", correlationId, ex);
        var pd = ProblemDetail.forStatusAndDetail(
            HttpStatus.INTERNAL_SERVER_ERROR, "An unexpected error occurred");
        pd.setTitle("Internal server error");
        pd.setProperty("correlationId", correlationId); // client quotes this to support
        return pd;
    }
}
